@@ -0,0 +1,36 @@
+/**
+ *
+ * Tests for ReposManager
+ *
+ * @see https://github.com/react-boilerplate/react-boilerplate/tree/master/docs/testing
+ *
+ */
+
+import React from 'react';
+import { render } from '@testing-library/react';
+import { Provider } from 'react-redux';
+
+import ReposManager from '../index';
+import configureStore from '../../../configureStore';
+
+const renderReposManager = store =>
+  render(
+    <Provider store={store}>
+      <ReposManager />
+    </Provider>,
+  );
+
+describe('<ReposManager />', () => {
+  let store;
+
+  beforeEach(() => {
+    store = configureStore({});
+  });
+
+  it('should render and match the snapshot', () => {
+    const {
+      container: { firstChild },
+    } = renderReposManager(store);
+    expect(firstChild).toMatchSnapshot();
+  });
+});

diff --git a/app/containers/ReposManager/tests/saga.test.js b/app/containers/ReposManager/tests/saga.test.js
new file mode 100644
index 0000000..279429d
--- /dev/null
+++ b/app/containers/ReposManager/tests/saga.test.js
@@ -0,0 +1,70 @@
+/**
+ * Tests for ReposManager sagas
+ */
+
+import { put, takeLatest } from 'redux-saga/effects';
+
+import { loadRepos, reposLoaded, repoLoadingError } from '../slice';
+
+import githubData, { getRepos, addRepoOwnershipKey } from '../saga';
+
+const username = 'username';
+
+const repos = [
+  {
+    name: 'First repo',
+    owner: {
+      login: 'react-boilerplate',
+    },
+  },
+  {
+    name: 'Second repo',
+    owner: {
+      login: 'react-boilerplate',
+    },
+  },
+];
+
+const reposWithOwnershipKeys = addRepoOwnershipKey({ username, repos });
+
+/* eslint-disable redux-saga/yield-effects */
+describe('getRepos Saga', () => {
+  let getReposGenerator;
+
+  // We have to test twice, once for a successful load and once for an unsuccessful one
+  // so we do all the stuff that happens beforehand automatically in the beforeEach
+  beforeEach(() => {
+    getReposGenerator = getRepos();
+
+    const selectDescriptor = getReposGenerator.next().value;
+    expect(selectDescriptor).toMatchSnapshot();
+
+    const requestDescriptor = getReposGenerator.next(username).value;
+    expect(requestDescriptor).toMatchSnapshot();
+
+    const addRepoOwnershipKeyDescriptor = getReposGenerator.next(repos).value;
+    expect(addRepoOwnershipKeyDescriptor).toMatchSnapshot();
+  });
+
+  it('should dispatch the reposLoaded action if it requests the data successfully', () => {
+    const putDescriptor = getReposGenerator.next(reposWithOwnershipKeys).value;
+    expect(putDescriptor).toEqual(
+      put(reposLoaded({ repos: reposWithOwnershipKeys })),
+    );
+  });
+
+  it('should call the repoLoadingError action if the response errors', () => {
+    const putDescriptor = getReposGenerator.throw(new Error('Some error'))
+      .value;
+    expect(putDescriptor).toEqual(put(repoLoadingError()));
+  });
+});
+
+describe('githubDataSaga Saga', () => {
+  const githubDataSaga = githubData();
+
+  it('should start task to watch for LOAD_REPOS action', () => {
+    const takeLatestDescriptor = githubDataSaga.next().value;
+    expect(takeLatestDescriptor).toEqual(takeLatest(loadRepos.type, getRepos));
+  });
+});

diff --git a/app/components/Header/tests/HeaderLink.test.js b/app/components/Header/tests/HeaderLink.test.js
new file mode 100644
index 0000000..88dd9c4
--- /dev/null
+++ b/app/components/Header/tests/HeaderLink.test.js
@@ -0,0 +1,30 @@
+import React from 'react';
+import { render } from '@testing-library/react';
+import { MemoryRouter } from 'react-router-dom';
+import 'jest-styled-components';
+
+import HeaderLink from '../HeaderLink';
+
+const renderComponent = (props = {}) => {
+  const utils = render(
+    <MemoryRouter>
+      <HeaderLink to="/test" {...props}>
+        HeaderLink
+      </HeaderLink>
+    </MemoryRouter>,
+  );
+  const headerLink = utils.queryByText('HeaderLink');
+  return { ...utils, headerLink };
+};
+
+describe('<HeaderLink />', () => {
+  it('should match the snapshot', () => {
+    const { container } = renderComponent();
+    expect(container.firstChild).toMatchSnapshot();
+  });
+
+  it('should have a class attribute', () => {
+    const { headerLink } = renderComponent();
+    expect(headerLink).toHaveAttribute('class');
+  });
+});

